export interface PlantDiagnosis {
  plantName: string;
  scientificName: string;
  status: 'Healthy' | 'Diseased' | 'Stressed' | 'Unknown';
  confidenceScore: number;
  conditionName: string;
  description: string;
  immediateActions: string[];
  organicTreatment: string;
