import { GoogleGenAI } from "@google/genai";
import { PlantDiagnosis, Supplier } from "../types";

export const diagnosePlant = async (
  imageBase64: string, 
  location?: { latitude: number; longitude: number }
): Promise<PlantDiagnosis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Note: Using gemini-2.5-flash because Google Maps grounding is only supported in 2.5 series.
  // We must not use responseSchema or responseMimeType when using googleMaps tool.
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: imageBase64,
          },
        },
        {
          text: `Act as a world-class digital botanist and agricultural supply expert in Zimbabwe. 
          1. Analyze this plant image. Identify the plant and detect any diseases, nutrient deficiencies, or pest infestations.
          2. Provide scientific names and actionable organic and chemical treatment advice.
          3. BASED ON THE TREATMENT NEEDED (e.g. specific fungicide or pesticide), find the 3 nearest agricultural supply stores in Zimbabwe (look for "Agro-dealers", "Farm supplies", "Agricura", "Windmill", or "ZFC") relative to the user's current coordinates.
          4. If no specific agro-dealer is found, suggest the nearest major business center in Zimbabwe where these are sold (like Mbare Musika for Harare, Renkini for Bulawayo, or Sakubva for Mutare).

          YOU MUST RETURN THE RESPONSE AS A VALID JSON OBJECT ONLY. DO NOT INCLUDE MARKDOWN BLOCKS OR OTHER TEXT.

          JSON structure:
          {
            "plantName": string,
            "scientificName": string,
            "status": "Healthy" | "Diseased" | "Stressed" | "Unknown",
            "confidenceScore": number,
            "conditionName": string,
            "description": string,
            "immediateActions": string[],
            "organicTreatment": string,
            "chemicalTreatment": string,
            "preventionTips": string[],
            "suppliers": [
              { "name": string, "distance": string, "directionsUrl": string }
            ]
          }`
        }
      ]
    },
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: location ? {
            latitude: location.latitude,
            longitude: location.longitude
          } : undefined
        }
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("Failed to get diagnosis from AI");
  }

  try {
    // Attempt to parse JSON. Sometimes model includes markdown wrappers despite instructions.
    const cleanJson = text.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleanJson) as PlantDiagnosis;

    // Enrich directions URLs from grounding chunks if the model didn't provide them accurately
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks && parsed.suppliers) {
      parsed.suppliers = parsed.suppliers.map((s, idx) => {
        const chunk = groundingChunks.find((c: any) => c.maps?.title?.toLowerCase().includes(s.name.toLowerCase()));
        if (chunk?.maps?.uri) {
          return { ...s, directionsUrl: chunk.maps.uri };
        }
        return s;
      });
    }

    return parsed;
  } catch (e) {
    console.error("JSON Parse Error:", e, "Raw text:", text);
    throw new Error("Invalid response format from AI");
  }
};

