import React, { useState, useEffect, useRef } from 'react';
import { Plus, Leaf, Loader2, Sparkles, Sprout, Upload, MapPin } from 'lucide-react';
import CameraView from './components/CameraView';
import DiagnosisCard from './components/DiagnosisCard';
import HistoryBar from './components/HistoryBar';
import { diagnosePlant } from './services/geminiService';
import { PlantDiagnosis, DiagnosisHistoryItem } from './types';

const STORAGE_KEY = 'botanist_ai_history';

const App: React.FC = () => {
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [currentDiagnosis, setCurrentDiagnosis] = useState<PlantDiagnosis | null>(null);
  const [history, setHistory] = useState<DiagnosisHistoryItem[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [location, setLocation] = useState<{ latitude: number; longitude: number } | undefined>();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load history and geolocation on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setHistory(JSON.parse(saved));
    }

    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setLocation({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
        (err) => console.warn("Geolocation denied or unavailable:", err),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  const saveToHistory = (diagnosis: PlantDiagnosis, image: string) => {
    const newItem: DiagnosisHistoryItem = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      image,
      diagnosis
    };
    const updatedHistory = [newItem, ...history].slice(0, 5);
    setHistory(updatedHistory);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedHistory));
  };

  const handleCapture = async (base64Image: string) => {
    setIsCameraOpen(false);
    setIsAnalyzing(true);
    setError(null);

    try {
      // Re-fetch location just in case it wasn't ready
      let finalLoc = location;
      if (!finalLoc && navigator.geolocation) {
        try {
          const pos = await new Promise<GeolocationPosition>((res, rej) => 
            navigator.geolocation.getCurrentPosition(res, rej, { timeout: 3000 })
          );
          finalLoc = { latitude: pos.coords.latitude, longitude: pos.coords.longitude };
          setLocation(finalLoc);
        } catch (e) {
          console.warn("Could not fetch location for diagnosis context");
        }
      }

      const result = await diagnosePlant(base64Image, finalLoc);
      setCurrentDiagnosis(result);
      saveToHistory(result, base64Image);
    } catch (err) {
      setError("Diagnosis failed. Please ensure the plant is clearly visible and try again.");
      console.error(err);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      handleCapture(base64String);
    };
    reader.readAsDataURL(file);
    event.target.value = '';
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="min-h-screen pb-32">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileUpload} 
        accept="image/*" 
        className="hidden" 
      />

      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-emerald-50">
        <div className="max-w-xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-500 rounded-lg flex items-center justify-center">
              <Sprout className="text-white" size={18} />
            </div>
            <h1 className="text-lg font-bold text-slate-900">Botanist AI</h1>
          </div>
          <div className="flex items-center gap-3">
            {location && (
              <div className="flex items-center gap-1 text-[10px] bg-slate-100 text-slate-500 px-2 py-1 rounded-full border border-slate-200">
                <MapPin size={10} className="text-emerald-500" />
                <span>Loc Active</span>
              </div>
            )}
            <button 
              onClick={() => {
                setCurrentDiagnosis(null);
                setError(null);
              }}
              className="text-xs font-medium text-emerald-600 hover:bg-emerald-50 px-3 py-1 rounded-full transition-colors"
            >
              Clear
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-xl mx-auto px-6 py-8">
        {!isAnalyzing && !currentDiagnosis && !error && (
          <div className="text-center py-12 px-6">
            <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-6">
              <Leaf className="text-emerald-500" size={32} />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Ready to heal your plants?</h2>
            <p className="text-slate-500 mb-8 max-w-xs mx-auto">
              Capture or upload a clear photo of the leaves or stems for a botanical diagnosis and local supplier search.
            </p>
            <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-2xl flex items-start gap-3 text-left mb-8">
              <Sparkles className="text-emerald-600 shrink-0" size={20} />
              <p className="text-xs text-emerald-800 leading-relaxed">
                Powered by Gemini 2.5 Flash for disease detection and Google Maps grounding to find the closest Zimbabwe agro-dealers.
              </p>
            </div>
          </div>
        )}

        {isAnalyzing && (
          <div className="flex flex-col items-center justify-center py-20 animate-pulse">
            <div className="relative">
              <div className="absolute inset-0 bg-emerald-400 rounded-full blur-xl opacity-20 animate-ping" />
              <Loader2 className="animate-spin text-emerald-500 mb-6 h-12 w-12" />
            </div>
            <h3 className="text-lg font-bold text-slate-800">Analyzing Specimen</h3>
            <p className="text-sm text-slate-500 mt-2">Connecting to Digital Botanist Network...</p>
            <p className="text-[10px] text-slate-400 mt-1">Locating nearest Zimbabwe agro-dealers...</p>
          </div>
        )}

        {error && (
          <div className="bg-red-50 border border-red-100 p-6 rounded-3xl text-center mb-8">
            <h3 className="text-red-800 font-bold mb-2">Analysis Interrupted</h3>
            <p className="text-red-600 text-sm mb-4">{error}</p>
            <div className="flex gap-3 justify-center">
              <button 
                onClick={() => setIsCameraOpen(true)}
                className="bg-red-100 text-red-800 px-4 py-2 rounded-full text-sm font-bold"
              >
                Retry Scan
              </button>
              <button 
                onClick={triggerFileUpload}
                className="bg-red-50 text-red-700 px-4 py-2 rounded-full text-sm font-bold border border-red-200"
              >
                Upload Instead
              </button>
            </div>
          </div>
        )}

        {currentDiagnosis && (
          <DiagnosisCard diagnosis={currentDiagnosis} />
        )}

        <HistoryBar 
          items={history} 
          onSelectItem={(item) => {
            setCurrentDiagnosis(item.diagnosis);
            window.scrollTo({ top: 0, behavior: 'smooth' });
          }} 
        />
      </main>

      <div className="fixed bottom-8 left-0 right-0 px-6 flex justify-center pointer-events-none gap-3">
        <button
          onClick={triggerFileUpload}
          className="pointer-events-auto flex items-center justify-center w-14 h-14 bg-white border border-slate-200 text-slate-700 rounded-full shadow-lg active:scale-95 transition-transform"
          title="Upload Photo"
        >
          <Upload size={24} />
        </button>
        <button
          onClick={() => setIsCameraOpen(true)}
          className="pointer-events-auto flex items-center gap-3 bg-slate-900 text-white px-8 py-4 rounded-full shadow-2xl shadow-emerald-900/20 active:scale-95 transition-transform group"
        >
          <Plus className="group-hover:rotate-90 transition-transform" />
          <span className="font-bold tracking-tight">Start Scanning</span>
        </button>
      </div>

      {isCameraOpen && (
        <CameraView 
          onCapture={handleCapture} 
          onClose={() => setIsCameraOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;
